import BaseLog = require('./lib/dts');

declare class Log extends BaseLog {
    toSyslog():void;
    toFile(filename: string): void;
    minLevel: string;
    enableUncaughtAndUnhandled():void;
    disableUncaughtAndUnhandled():void;
    setDefaultLogDir(dir:string, callback?:Function):void;
    enableDebug(name:string|RegExp, level:string):void;
    createChild(namespace:string):Log;
    debug(...args:any[]):Log;
    info(...args:any[]):Log;
    warn(...args:any[]):Log;
    error(...args:any[]):Log;
    iferr(err:any, ...args:any[]):Log;
}

export = Log;
